function getPlayerPortraitModel(player: Pick<Player, "id" | "name" | "portraitUrl" | "portraitPath">) {
  const src = getPlayerPortraitBrowserUrl(player.id, player.portraitUrl, player.portraitPath);
  const initials = player.name
    .split(/\s+/)
    .filter(Boolean)
    .slice(0, 2)
    .map((part) => part[0]?.toUpperCase() ?? "")
    .join("") || "?";

  return { src, initials };
}

function PlayerPortrait({
  src,
  initials,
  alt,
  className,
  style,
  loading = "lazy",
  fetchPriority = "low",
}: {
  src: string | null;
  initials: string;
  alt: string;
  className: string;
  style?: CSSProperties;
  loading?: "eager" | "lazy";
  fetchPriority?: "high" | "low" | "auto";
}) {
  const [failed, setFailed] = useState(false);
  if (!src || failed) {
    return (
      <span className={`${className} transfermarkt-portrait-placeholder`} aria-label={`${alt} Platzhalter`} style={style}>
        {initials}
      </span>
    );
  }

  return (
    <img
      className={className}
      src={src}
      alt={alt}
      style={style}
      loading={loading}
      decoding="async"
      fetchPriority={fetchPriority}
      onError={() => setFailed(true)}
    />
  );
}

function getTransferTypeLabel(type: "buy" | "sell" | "contract_exit") {
  if (type === "contract_exit") return "Contract Exit";
  return type === "buy" ? "Kauf" : "Verkauf";
}

function getTransferTypePillClass(type: "buy" | "sell" | "contract_exit") {
  return `transfer-status-pill ${type === "buy" ? "is-ready" : "is-warning"}`;
}

function joinClassNames(...classes: Array<string | false | null | undefined>) {
  return classes.filter(Boolean).join(" ");
}

function isAbortError(error: unknown) {
  return error instanceof DOMException
    ? error.name === "AbortError"
    : error instanceof Error && error.name === "AbortError";
}

function getOwnerTeamHighlightClass(settings: TeamControlSettings | null | undefined) {
  if (settings?.controlMode !== "manual") {
    return "";
  }
  if (settings.ownerId === DEFAULT_ACTIVE_OWNER_ID) {
    return "is-owner-user-team";
  }
  if (settings.ownerId === "franky_remote_placeholder") {
    return "is-owner-franky-team";
  }
  return "";
}

function formatTeamControlModeLabel(mode: TeamControlMode | null | undefined) {
  if (mode === "manual") return "geführt";
  if (mode === "ai") return "automatisch";
  if (mode === "passive") return "beobachtet";
  return "offen";
}

function getRanksMetricToneClass(columnId: string, scope: "head" | "cell") {
  const prefix = scope === "head" ? "ranks-head-metric" : "ranks-metric-cell";
  if (columnId === "totalRank") return `${prefix} ${prefix}-total ranks-summary-block-start`;
  if (columnId === "powRank") return `${prefix} ${prefix}-pow`;
  if (columnId === "speRank") return `${prefix} ${prefix}-spe`;
  if (columnId === "menRank") return `${prefix} ${prefix}-men`;
  if (columnId === "socRank") return `${prefix} ${prefix}-soc ranks-summary-block-end`;
  return "";
}

function getTransferSourceLabel(source: string | null | undefined) {
  if (!source) {
    return "—";
  }

  const labels: Record<string, string> = {
    manual_transfermarkt_buy: "Manual Buy",
    manual_transfermarkt_sell: "Manual Sell",
    auto_roster_fill: "Setup / Auto Roster Fill",
    ai_roster_fill: "Setup / AI Roster Fill",
    smoke_setup: "Smoke/Setup",
  };

  return labels[source] ?? source.replaceAll("_", " ");
}

function getTeamLogoModel(team: Pick<Team, "teamId" | "name" | "logoPath">) {
  const src =
    [team.logoPath].find((value) => typeof value === "string" && value.length > 0 && !value.startsWith("/Users/")) ??
    (team.logoPath?.startsWith("/Users/") ? `/api/media/team-logo/${encodeURIComponent(team.teamId)}` : null);

  const initials = team.name
    .split(/\s+/)
    .filter(Boolean)
    .slice(0, 2)
    .map((part) => part[0]?.toUpperCase() ?? "")
    .join("") || "?";

  return { src, initials };
}

