function withNormalizedLocalTeamSettings(gameState: GameState): GameState {
  return withNormalizedTeamStrategyProfiles(
    withNormalizedTeamControlSettings(
      withNormalizedTeamGeneralManagers(withNormalizedTeamIdentityOverrides(gameState)),
    ),
  );
}

function buildTeamIdentityDraftMap(teams: Team[], teamIdentities: TeamIdentity[]) {
  const byTeamId = new Map(teamIdentities.map((identity) => [identity.teamId, identity] as const));
  return Object.fromEntries(
    teams.flatMap((team) => {
      const identity = byTeamId.get(team.teamId);
      return identity ? [[team.teamId, identity] as const] : [];
    }),
  );
}

function clampIdentityValue(value: number, key: keyof TeamIdentity) {
  if (!Number.isFinite(value)) {
    return 0;
  }

  const rounded = Math.round(value * 10) / 10;
  if (key === "playerMin" || key === "playerOpt") {
    return Math.max(0, Math.min(32, Math.round(rounded)));
  }

  return Math.max(0, Math.min(20, rounded));
}

function formatIdentityWeight(value: number | null | undefined) {
  return typeof value === "number" && Number.isFinite(value) ? `${Math.round(value)}%` : "—";
}

function parseCsvList(value: string) {
  return value
    .split(",")
    .map((entry) => entry.trim())
    .filter(Boolean);
}

function formatCsvList(values: string[] | null | undefined) {
  return values?.join(", ") ?? "";
}

function getTeamRosterRoleBucket(roleTag: string | null | undefined): Exclude<TeamRosterRoleFilter, "all"> {
  const normalized = (roleTag ?? "").toLowerCase();
  if (normalized.includes("starter") || normalized.includes("star") || normalized.includes("core")) {
    return "starter";
  }
  if (normalized.includes("rotation")) {
    return "rotation";
  }
  if (normalized.includes("prospect")) {
    return "prospect";
  }
  if (normalized.includes("bench") || normalized.includes("bank")) {
    return "bench";
  }
  return "other";
}

function clampBiasValue(value: number) {
  if (!Number.isFinite(value)) {
    return 5;
  }
  return Math.max(1, Math.min(10, Math.round(value)));
}

function normalizeTeamStrategyLevel(value: string): "low" | "medium" | "high" {
  return value === "low" || value === "high" ? value : "medium";
}

function withSynchronizedStrategyAliases(current: TeamStrategyProfile, patch: Partial<TeamStrategyProfile>): TeamStrategyProfile {
  const next = {
    ...current,
    ...patch,
  };

  if (patch.dislikedArchetypes) {
    next.avoidedArchetypes = patch.dislikedArchetypes;
  }
  if (patch.dislikedRaces) {
    next.avoidedRaces = patch.dislikedRaces;
  }
  if (patch.dislikedClasses) {
    next.avoidedClasses = patch.dislikedClasses;
  }
  if (patch.lockedNoGos) {
    next.hardNoGos = patch.lockedNoGos;
  }

  return next;
}

const foundationBootWatchdogScript = `
(function () {
  if (window.__foundationBootWatchdogActive) return;
  window.__foundationBootWatchdogActive = true;
  window.setTimeout(function () {
    try {
      var key = "foundation_boot_reload_once";
      if (!window.sessionStorage.getItem(key)) {
        window.sessionStorage.setItem(key, "1");
        window.location.reload();
        return;
      }
    } catch (error) {}
  }, 6000);
})();
`;

