        if (id !== stepId) {
          return stored ?? { stepId: id, status: "open" as const };
        }

        return {
          stepId: id,
          status,
          completedAt: status === "completed" ? now : stored?.completedAt ?? null,
          skippedAt: status === "skipped" ? now : stored?.skippedAt ?? null,
        };
